var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"그렇게 머리 쓰는 표정 지을 필요 없네.","JPN":"そんなに考え込むことはない。","ENG":"There’s no need to act like you’re deliberating.","TWN":"不需要露出那麼傷腦筋的樣子。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"협상을 위한 자리라고는 했지만 내 쪽에서 뭔가를 요구할 생각은 없어.","JPN":"交渉のためにとは言っていたが、こちらから何かを要求するつもりはないからな。","ENG":"You may have called it a negotiation, but I have no intention of making any demands.","TWN":"雖然這是個談判的場合，但我沒打算要求什麼。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"내 협력이 필요하다면 부담 갖지 말고 맡겨주게. 그게 내가 바라는 전부야.","JPN":"私の協力が必要なら、いつでも任せてくれ。それが私の望みだ。","ENG":"If you need my assistance, feel free to request. That’s all I ask for.","TWN":"我只希望，你若需要我的協助，就儘管開口，無須客氣。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"우리가 지금 이 방에서 나누는 대화는, 자네 회사가 논하는 비즈니스의 사정도… 내 신분의 정치적인 문제와도 상관없는 얘기일세.","JPN":"私たちが今この部屋で交わす会話は、君の会社のビジネス的な事情も……私の政治的な立場とも関係ない。","ENG":"This conversation that we’re having in this room right now has nothing to do with your company’s business or the political ramifications of my position.","TWN":"我們在這房間裡的談話，與你在公司談的公事…和我在政治上的身分都無關。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"난 델타세븐을 대표하는 장군이 아닌 마리아 안토노프라는 한 사람으로서 자네에게 말하고 있는 거야.","JPN":"私はデルタセブンを代表する将軍ではなく、マリア・アントノフという一人の人として君に言っているのだ。","ENG":"I’m speaking to you as Maria Antonov, not the general representing Delta Seven.","TWN":"我現在不是以第七三角洲將軍的身分，而是以瑪麗亞·安東諾夫的身分在和你對話。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"자네가 말한 앞으로 벌어질 일들에 대비하려면… 계약이라는 결속만으론 부족할 테니까.","JPN":"君が言っていたこれからのことに備えるには……契約という結束では足りないだろうからな。","ENG":"In order to prepare for the future events that you shared with me... It’ll take more than just a contract.","TWN":"若要防範你所說那些將來會發生的事…光憑一紙合約是不夠的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"그러니 난 자네에게 내 모든 걸 맡기도록 하지. 후회는 하지 않아.","JPN":"だから、私のすべてを君に託そう。後悔はしない。","ENG":"Therefore, I leave my everything in your hands. I have no regrets.","TWN":"所以我決定將我的一切託付給你，我不會後悔的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"오늘을 계기로, 자네가 날 완전히 신뢰할 수 있는 날이 오길 바라지.","JPN":"今日をきっかけに、君が私を完全に信頼できる日が来ることを祈ろう。","ENG":"Following today, I hope that the day will come when you completely trust me.","TWN":"趁今天這個機會，希望總有一天你能夠完全地信任我。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};